        const nav = document.getElementById('nav');
        const content = document.getElementById('content');
        const title = document.getElementById('title');

        let currentSelected = null;

        function show(item, type) {
            currentSelected = { item, type };
            document.querySelectorAll('.nav-item').forEach(e => e.classList.remove('active'));
            const id = type + '-' + (item.file || item.title).replace(/\s/g, '_');
            const navEl = document.getElementById(id);
            if (navEl) navEl.classList.add('active');
            
            title.innerText = item.title;
            
            let mdContent = item.content || '';
            let mermaidBlocks = [];
            let mathBlocks = [];
            
            // Extract Mermaid
            mdContent = mdContent.replace(/```mermaid([\s\S]*?)```/g, function(match, code) {
                mermaidBlocks.push(code.trim());
                return `%%MERMAID_BLOCK_${mermaidBlocks.length - 1}%%`;
            });

            // Extract Math
            mdContent = mdContent.replace(/\$\$([\s\S]*?)\$\$/g, function(match) {
                mathBlocks.push(match);
                return `%%MATH_BLOCK_${mathBlocks.length - 1}%%`;
            });
            mdContent = mdContent.replace(/\$([^\$]+?)\$/g, function(match) {
                mathBlocks.push(match);
                return `%%MATH_BLOCK_${mathBlocks.length - 1}%%`;
            });
            
            let htmlContent = marked.parse(mdContent);
            
            // Re-inject Mermaid
            mermaidBlocks.forEach((code, idx) => {
                htmlContent = htmlContent.replace(`%%MERMAID_BLOCK_${idx}%%`, '<div class="mermaid-box"><div class="mermaid">' + code + '</div></div>');
            });
            // Re-inject Math placeholders
            mathBlocks.forEach((code, idx) => {
                htmlContent = htmlContent.replace(`%%MATH_BLOCK_${idx}%%`, code);
            });
            
            content.innerHTML = htmlContent;
            document.querySelector('.main').scrollTop = 0;
            
            setTimeout(async () => {
                try {
                    renderMathInElement(content, {
                        delimiters: [
                            {left: '$$', right: '$$', display: true},
                            {left: '$', right: '$', display: false}
                        ],
                        throwOnError : false
                    });
                    // Use modern mermaid.run instead of init
                    await mermaid.run({
                        querySelector: '.mermaid',
                    });
                } catch(e) { 
                    console.error("Rendering error:", e);
                    // Fallback for older mermaid versions or specific errors
                    try { mermaid.init(undefined, document.querySelectorAll('.mermaid')); } catch(i) {}
                }
            }, 100);
        }

        function addHeader(text) {
            const h = document.createElement('div');
            h.style = "font-size: 11px; color: var(--secondary); font-weight: bold; margin: 20px 0 10px 5px; letter-spacing: 1px; opacity: 0.8";
            h.innerText = text;
            nav.appendChild(h);
        }

        function addItem(item, type) {
            const div = document.createElement('div');
            div.id = type + '-' + (item.file || item.title).replace(/\s/g, '_');
            div.className = 'nav-item';
            // Show title and filename in brackets for clarity
            const displayTitle = item.title + (item.file ? ` [${item.file}]` : '');
            div.innerText = displayTitle;
            div.onclick = () => show(item, type);
            nav.appendChild(div);
            return div;
        }

        if (data.chapters && data.chapters.length > 0) {
            addHeader("CÁC CHƯƠNG CHI TIẾT");
            data.chapters.forEach(ch => addItem(ch, 'ch'));
        }

        if (data.standalones && data.standalones.length > 0) {
            addHeader("CÁC BẢN ĐỀ CƯƠNG ĐẦY ĐỦ");
            data.standalones.forEach(st => addItem(st, 'st'));
        }

        if (data.others && data.others.length > 0) {
            addHeader("TÀI LIỆU HƯỚNG DẪN & KHÁC");
            data.others.forEach(ot => addItem(ot, 'ot'));
        }

        if (data.lastUpdated) {
            document.getElementById('update-time').innerText = "Cập nhật: " + data.lastUpdated;
        }
        
        mermaid.initialize({startOnLoad: false, theme: 'neutral'});
        
        if (data.chapters && data.chapters.length > 0) {
            show(data.chapters[0], 'ch');
        } else if (data.standalones && data.standalones.length > 0) {
            show(data.standalones[0], 'st');
        }

        function getFullContentHTML() {
            let html = '';
            let targetItems = [];
            let mainTitle = "ĐỀ CƯƠNG TIẾN SĨ - LÊ PHÚC HẢI";

            if (currentSelected && currentSelected.type === 'st') {
                targetItems = [currentSelected.item];
                mainTitle = currentSelected.item.title;
            } else {
                targetItems = data.chapters || [];
            }

            html += `<h1 class="export-title">${mainTitle}</h1>`;
            
            targetItems.forEach(ch => {
                let mdContent = ch.content || '';
                let mermaidBlocks = [];
                let mathBlocks = [];
                
                mdContent = mdContent.replace(/```mermaid([\s\S]*?)```/g, function(match, code) {
                    mermaidBlocks.push(code.trim());
                    return `%%MERMAID_BLOCK_${mermaidBlocks.length - 1}%%`;
                });
                
                mdContent = mdContent.replace(/\$\$([\s\S]*?)\$\$/g, function(match) {
                    mathBlocks.push(match);
                    return `%%MATH_BLOCK_${mathBlocks.length - 1}%%`;
                });
                mdContent = mdContent.replace(/\$([^\$]+?)\$/g, function(match) {
                    mathBlocks.push(match);
                    return `%%MATH_BLOCK_${mathBlocks.length - 1}%%`;
                });
                
                let parsedContent = marked.parse(mdContent);
                
                mermaidBlocks.forEach((code, idx) => {
                    parsedContent = parsedContent.replace(`%%MERMAID_BLOCK_${idx}%%`, '<div class="mermaid">' + code + '</div>');
                });
                mathBlocks.forEach((code, idx) => {
                    parsedContent = parsedContent.replace(`%%MATH_BLOCK_${idx}%%`, code);
                });

                html += `<div class="export-chapter">${parsedContent}</div>`;
                html += '<div class="page-break"></div>';
            });
            return html;
        }

        async function exportWord() {
            const btn = document.querySelector('button[onclick="exportWord()"]');
            const originalText = btn.innerText;
            btn.innerText = "Đang xử lý...";

            const tempDiv = document.createElement('div');
            tempDiv.id = "word-export-container";
            tempDiv.innerHTML = getFullContentHTML();
            document.body.appendChild(tempDiv);

            const style = document.createElement('style');
            style.innerHTML = `
                #word-export-container { font-family: 'Times New Roman', serif; font-size: 14pt; color: black !important; background: white; padding: 40px; width: 800px; position: absolute; left: -10000px; }
                #word-export-container h1, #word-export-container h2 { color: black !important; }
                #word-export-container table { border-collapse: collapse; width: 100%; }
                #word-export-container th, #word-export-container td { border: 1px solid black; padding: 8px; color: black !important; }
            `;
            document.head.appendChild(style);

            try {
                // 1. Xử lý công thức toán học thành MathML cho Word
                try {
                    if (typeof renderMathInElement !== 'undefined') {
                        renderMathInElement(tempDiv, {
                            delimiters: [{left: '$$', right: '$$', display: true}, {left: '$', right: '$', display: false}],
                            throwOnError : false, output: 'mathml'
                        });
                    }
                } catch (e) { console.warn("Math render failed", e); }
                
                // 2. Render Mermaid
                try {
                    await mermaid.run({ nodes: tempDiv.querySelectorAll('.mermaid') });
                } catch (mErr) {
                    console.warn("Mermaid run failed in export, trying fallback:", mErr);
                    try { await mermaid.init(undefined, tempDiv.querySelectorAll('.mermaid')); } catch(e) {}
                }
                
                await new Promise(r => setTimeout(r, 1000));

                // 3. Chuẩn hóa bảng cho Word
                tempDiv.querySelectorAll('table').forEach(tbl => {
                    tbl.setAttribute('border', '1');
                    tbl.setAttribute('cellspacing', '0');
                    tbl.setAttribute('cellpadding', '8');
                    tbl.style.borderCollapse = 'collapse';
                    tbl.style.width = '100%';
                    tbl.style.marginBottom = '20px';
                    tbl.querySelectorAll('th, td').forEach(cell => {
                        cell.style.border = '1px solid black';
                        cell.style.padding = '8px';
                    });
                });

                // 4. Xử lý biểu đồ SVG thành PNG nhúng trực tiếp (Base64)
                const svgs = tempDiv.querySelectorAll('.mermaid svg');
                for (let svg of svgs) {
                    try {
                        const svgData = new XMLSerializer().serializeToString(svg);
                        const canvas = document.createElement('canvas');
                        const ctx = canvas.getContext('2d');
                        const img = new Image();
                        
                        let w = svg.viewBox && svg.viewBox.baseVal ? svg.viewBox.baseVal.width : 800;
                        let h = svg.viewBox && svg.viewBox.baseVal ? svg.viewBox.baseVal.height : 400;
                        if (w === 0) w = 800;
                        if (h === 0) h = 400;
                        
                        canvas.width = w * 2; canvas.height = h * 2;

                        await new Promise((resolve) => {
                            img.onload = () => {
                                ctx.fillStyle = "white"; ctx.fillRect(0, 0, canvas.width, canvas.height);
                                ctx.drawImage(img, 0, 0, canvas.width, canvas.height);
                                const base64Data = canvas.toDataURL("image/png");
                                const newImg = document.createElement('img');
                                newImg.setAttribute('src', base64Data);
                                newImg.style.width = w + "px";
                                svg.parentNode.replaceChild(newImg, svg);
                                resolve();
                            };
                            img.onerror = (err) => { 
                                console.error("SVG convert error", err);
                                resolve(); 
                            };
                            img.src = "data:image/svg+xml;base64," + btoa(unescape(encodeURIComponent(svgData)));
                        });
                    } catch (err) {
                        console.warn("SVG error", err);
                    }
                }

                // 5. CSS dành cho Word
                const wordStyles = `
                    <style>
                        @page WordSection1 { size: A4; margin: 2.5cm 2.0cm 2.5cm 3.5cm; mso-header-margin: 1.25cm; mso-footer-margin: 1.25cm; mso-paper-source: 0; }
                        div.WordSection1 { page: WordSection1; }
                        table { border-collapse: collapse; width: 100%; margin-bottom: 20px; }
                        th, td { border: 1px solid black; padding: 8px; text-align: left; }
                        th { background-color: #f2f2f2; }
                        h1, h2, h3, h4 { font-family: 'Times New Roman', serif; color: black; margin-top: 12pt; margin-bottom: 6pt; }
                        p, li { font-family: 'Times New Roman', serif; font-size: 14pt; line-height: 1.5; text-align: justify; margin-top: 0pt; margin-bottom: 0pt; text-indent: 1cm; }
                        .export-title { text-align: center; font-size: 16pt; font-weight: bold; margin-bottom: 30px; text-transform: uppercase; }
                    </style>
                `;

                // Sử dụng BOM (\ufeff) để Word đọc đúng Unicode/Tiếng Việt
                const htmlContent = `\ufeff<html xmlns:o='urn:schemas-microsoft-com:office:office' xmlns:w='urn:schemas-microsoft-com:office:word' xmlns='http://www.w3.org/TR/REC-html40'>
                <head>
                    <meta charset='utf-8'>
                    <title>Export Word</title>
                    ${wordStyles}
                </head>
                <body style="font-family:'Times New Roman'">
                    <div class="WordSection1">${tempDiv.innerHTML}</div>
                </body>
                </html>`;

                // 6. Tạo file .doc và tải về
                const blob = new Blob([htmlContent], { type: 'application/msword;charset=utf-8' });
                const link = document.createElement('a');
                link.href = URL.createObjectURL(blob);
                
                let exportTitle = "LePhucHai";
                if (currentSelected && currentSelected.item && currentSelected.item.title) {
                    exportTitle = currentSelected.item.title;
                }
                let safeTitle = exportTitle.replace(/[^a-zA-Z0-9]/g, '_').substring(0, 30);
                link.download = `DeCuong_PhD_${safeTitle}.doc`;
                link.click();
            } catch (e) { 
                alert("Đã xảy ra lỗi khi xuất Word: " + e.message); 
                console.error(e);
            }
            finally {
                document.body.removeChild(tempDiv);
                document.head.removeChild(style);
                btn.innerText = originalText;
            }
        }

